const SCREEN_H = Dimensions.get('window').height;
export function PersistentMiniPlayerAboveTabBar({open, onClose, children}: {open: boolean; onClose: () => void; children: React.ReactNode}) {
  const snaps = useMemo(() => [SCREEN_H * 0.74, SCREEN_H * 0.38, SCREEN_H * 0.1], []);
  const y = useSharedValue(open ? snaps[1] : SCREEN_H);
  const pan = Gesture.Pan().onUpdate((e) => { y.value = Math.max(snaps[2], snaps[1] + e.translationY); }).onEnd((e) => { const projected = y.value + e.velocityY * 0.16; const next = snaps.reduce((best, snap) => Math.abs(projected - snap) < Math.abs(projected - best) ? snap : best, snaps[0]); y.value = withSpring(next, {damping: 22, stiffness: 220}); });
  const sheetStyle = useAnimatedStyle(() => ({transform: [{translateY: y.value}]}));
  const backdropStyle = useAnimatedStyle(() => ({opacity: interpolate(y.value, [snaps[0], snaps[2]], [0.08, 0.46])}));
  return <View pointerEvents={open ? 'auto' : 'none'} style={StyleSheet.absoluteFill}><Animated.View style={[styles.backdrop, backdropStyle]} /><GestureDetector gesture={pan}><Animated.View style={[styles.sheet, sheetStyle]} accessibilityViewIsModal accessibilityLabel="Persistent mini player above tab bar"><View style={styles.handle} /><Text style={styles.title}>Persistent mini player above tab bar</Text>{children}<Pressable onPress={onClose} accessibilityRole="button" style={styles.close}><Text>Close</Text></Pressable></Animated.View></GestureDetector></View>;
}
const styles = StyleSheet.create({backdrop: {...StyleSheet.absoluteFillObject, backgroundColor: 'black'}, sheet: {position: 'absolute', left: 0, right: 0, height: SCREEN_H, borderTopLeftRadius: 24, borderTopRightRadius: 24, backgroundColor: 'white', padding: 18, gap: 12}, handle: {alignSelf: 'center', width: 42, height: 5, borderRadius: 3, backgroundColor: '#cbd5e1'}, title: {fontSize: 18, fontWeight: '700'}, close: {minHeight: 44, justifyContent: 'center'}});

// DraggableFlashList.tsx
import React, { useState } from 'react';
import { FlashList } from '@shopify/flash-list';
import { Gesture, GestureDetector } from 'react-native-gesture-handler';

type Row = { id: string; title: string };

export function DraggableFlashList({ initial }: { initial: Row[] }) {
  const [rows, setRows] = useState(initial);
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const commit = (from: number, to: number) => setRows((current) => reorder(current, from, to));
  return (
    <FlashList
      data={rows}
      estimatedItemSize={64}
      keyExtractor={(row) => row.id}
      renderItem={({ item, index }) => (
        <GestureDetector gesture={longPressThenPan(item.id, index, commit, setDraggingId)}>
          <ReorderableRow row={item} dragging={draggingId === item.id} accessibilityActions={[{ name: 'moveUp' }, { name: 'moveDown' }]} />
        </GestureDetector>
      )}
    />
  );
}

